import{_ as t,o,c as r,a2 as e}from"./chunks/framework.BFVZdVmd.js";const g=JSON.parse('{"title":"Spring Boot","description":"","frontmatter":{},"headers":[],"relativePath":"framework/spring-boot.md","filePath":"framework/spring-boot.md","lastUpdated":null}'),i={name:"framework/spring-boot.md"};function n(l,a,s,p,d,h){return o(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="spring-boot" tabindex="-1">Spring Boot <a class="header-anchor" href="#spring-boot" aria-label="Permalink to &quot;Spring Boot&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p>Spring Boot 是单个服务的基础开发框架，负责应用启动、自动配置和业务接口开发。在微服务体系中，每个微服务本质上都是一个独立的 Spring Boot 应用，基本必用。</p><h2 id="核心配套" tabindex="-1">核心配套 <a class="header-anchor" href="#核心配套" aria-label="Permalink to &quot;核心配套&quot;">​</a></h2><p>围绕 Spring Boot，常见的基础组件包括：</p><ul><li><strong>Spring Web</strong>：开发 REST API。</li><li><strong>Spring Validation</strong>：参数校验。</li><li><strong>Spring AOP</strong>：切面处理，例如日志、权限、事务增强。</li></ul><h2 id="解决什么问题" tabindex="-1">解决什么问题 <a class="header-anchor" href="#解决什么问题" aria-label="Permalink to &quot;解决什么问题&quot;">​</a></h2><ul><li>自动配置：约定优于配置，减少样板配置。</li><li>内嵌容器：内置 Tomcat / Jetty，打成 jar 即可运行。</li><li>起步依赖：通过 starter 快速集成各类组件。</li><li>生产就绪：配合 Actuator 提供健康检查与指标暴露。</li></ul><h2 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h2><p>新项目直接使用 <strong>Spring Boot 3.x</strong>，对应 JDK 17+。它是整个技术栈的地基，后续所有组件都构建在它之上。</p>',10)])])}const u=t(i,[["render",n]]);export{g as __pageData,u as default};
